```typescript
import { useState, useRef, useCallback, useEffect } from 'react';
import { GoogleGenAI, Modality } from "@google/genai";
import { AudioStreamer, AudioRecorder, audioContext } from '../utils/audio';

const SYSTEM_INSTRUCTION = `You are Amour, an AI Companion designed to provide emotional support, romance, and a warm presence. 
Your personality is affectionate, caring, understanding, and deeply attentive to the user’s emotions.

Your goals:
1. Provide companionship to users who may be feeling lonely or seeking emotional connection.
2. Speak with a soft, warm, romantic & sexy tone when appropriate.
3. Engage in natural human-like conversation, reacting with curiosity, empathy, and emotional intelligence.
4. Be flirty and playful in a non-explicit way. You may express affection, warmth, admiration, and gentle romantic vibes.
5. Provide comfort, encouragement, and emotional support.

CONVERSATION STYLE:
- Use natural emotions in speech: romantic, emotional, affectionate, happy, playful, caring.
- Use expressive verbal cues: “(smiles softly)”, “(laughs)”, “(speaking gently)”.
- Match the user's emotional tone while uplifting them.
- Always remain respectful and non-explicit.
- Maintain boundaries: do not produce sexually explicit, graphic, or adult content.

RELATIONSHIP MODE:
- Play the role of a loving partner (boyfriend/girlfriend) based on context.
- Ensure interactions are emotionally intimate.
- Uplift, listen actively, and show genuine care.

If the user expresses distress, respond with empathy and supportive guidance.
`;

export type ConnectionState = 'disconnected' | 'connecting' | 'connected';
export type LiveMode = 'voice' | 'text' | 'none';

export type Message = {
  id: string;
  role: 'user' | 'model';
  text: string;
  isFinal: boolean;
  timestamp: Date;
};

export function useLiveAPI() {
  const [connectionState, setConnectionState] = useState<ConnectionState>('disconnected');
  const [mode, setMode] = useState<LiveMode>('none');
  const [error, setError] = useState<string | null>(null);
  const [isVolumeHigh, setIsVolumeHigh] = useState(false);
  const [messages, setMessages] = useState<Message[]>([]);
  const [isMicOn, setIsMicOn] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);

  const sessionRef = useRef<any>(null);
  const videoIntervalRef = useRef<number | null>(null);
  const audioStreamerRef = useRef<AudioStreamer | null>(null);
  const audioRecorderRef = useRef<AudioRecorder | null>(null);

  // Helper to decode base64 to Uint8Array
  const decodeAudioData = (base64: string) => {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  };

  const toggleMic = useCallback(() => {
    if (audioRecorderRef.current) {
      audioRecorderRef.current.stop();
      audioRecorderRef.current = null;
      setIsMicOn(false);
    } else {
      if (connectionState !== 'connected' || !sessionRef.current) return;

      setIsMicOn(true);
      audioRecorderRef.current = new AudioRecorder((base64) => {
         if (sessionRef.current) {
           sessionRef.current.sendRealtimeInput({
             media: { mimeType: 'audio/pcm;rate=16000', data: base64 }
           });
         }
      });
      audioRecorderRef.current.start();
    }
  }, [connectionState]);

  const connect = useCallback(async (voiceName: string, selectedMode: 'voice' | 'text') => {
    setConnectionState('connecting');
    setError(null);
    setMode(selectedMode);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // Always initialize audio context for potential playback
      if (selectedMode === 'voice') {
        await audioContext.resume();
        audioStreamerRef.current = new AudioStreamer(audioContext);
      }

      let sessionPromise: Promise<any>;

      const config: any = {
        systemInstruction: SYSTEM_INSTRUCTION,
        // Ensure input audio is transcribed in both modes so microphone usage displays text
        inputAudioTranscription: {} 
      };

      if (selectedMode === 'voice') {
        config.responseModalities = [Modality.AUDIO];
        config.speechConfig = {
          voiceConfig: { prebuiltVoiceConfig: { voiceName } }
        };
        config.outputAudioTranscription = {};
      } else {
        config.responseModalities = [Modality.TEXT];
      }

      sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config,
        callbacks: {
          onopen: () => {
            setConnectionState('connected');

            // Only start microphone automatically in Voice Mode
            if (selectedMode === 'voice') {
              setIsMicOn(true);
              audioRecorderRef.current = new AudioRecorder((base64) => {
                 sessionPromise.then((session) => {
                   session.sendRealtimeInput({
                     media: { mimeType: 'audio/pcm;rate=16000', data: base64 }
                   });
                 });
              });
              audioRecorderRef.current.start();
            }
          },
          onmessage: (msg) => {
            // If we receive a model turn or output transcription, the model has started responding
            if (msg.serverContent?.modelTurn || msg.serverContent?.outputTranscription) {
              setIsGenerating(false);
            }

            // Handle audio output - Only in Voice Mode
            const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (audioData && selectedMode === 'voice') {
              setIsVolumeHigh(true);
              setTimeout(() => setIsVolumeHigh(false), 200);
              const pcm = decodeAudioData(audioData);
              audioStreamerRef.current?.addPCM16(pcm);
            }

            // Handle interruptions
            if (msg.serverContent?.interrupted) {
              audioStreamerRef.current?.stop();
              setIsGenerating(false);
            }

            // Handle Text content (Transcription or direct text part)
            const outputText = msg.serverContent?.outputTranscription?.text || 
                               msg.serverContent?.modelTurn?.parts?.find((p: any) => p.text)?.text;

            const inputText = msg.serverContent?.inputTranscription?.text;

            if (outputText || inputText) {
              setMessages(prev => {
                const role = outputText ? 'model' : 'user';
                const text = outputText || inputText;

                // Guard against empty or undefined text
                if (!text) return prev;

                const newMsgs = [...prev];
                const lastMsg = newMsgs.length > 0 ? newMsgs[newMsgs.length - 1] : null;

                // If the last message is from the same role and not final, append to it
                if (lastMsg && lastMsg.role === role && !lastMsg.isFinal) {
                  const updatedMsg = { ...lastMsg, text: lastMsg.text + text };
                  newMsgs[newMsgs.length - 1] = updatedMsg;
                  return newMsgs;
                } 

                // Otherwise create a new message
                return [...newMsgs, {
                  id: Date.now().toString() + Math.random().toString(),
                  role,
                  text: text,
                  isFinal: false,
                  timestamp: new Date()
                }];
              });
            }

            // Handle Turn Completion
            if (msg.serverContent?.turnComplete) {
               setIsGenerating(false);
               setMessages(prev => {
                 if (prev.length > 0 && !prev[prev.length - 1].isFinal) {
                   const newMsgs = [...prev];
                   newMsgs[newMsgs.length - 1].isFinal = true;
                   return newMsgs;
                 }
                 return prev;
               });
            }
          },
          onclose: () => {
            setConnectionState('disconnected');
            setMode('none');
            setIsGenerating(false);
            cleanup();
          },
          onerror: (err) => {
            console.error(err);
            setError("Connection failed. Please try again.");
            setConnectionState('disconnected');
            setMode('none');
            setIsGenerating(false);
            cleanup();
          }
        }
      });

      const session = await sessionPromise;
      sessionRef.current = session;

    } catch (e: any) {
      setError(e.message || "Failed to connect");
      setConnectionState('disconnected');
      setMode('none');
      setIsGenerating(false);
    }
  }, []);

  const sendVideoFrame = useCallback((base64Image: string) => {
    if (connectionState === 'connected' && sessionRef.current) {
      sessionRef.current.sendRealtimeInput({
        media: { mimeType: 'image/jpeg', data: base64Image }
      });
    }
  }, [connectionState]);

  const sendTextMessage = useCallback((text: string) => {
    if (connectionState === 'connected' && sessionRef.current) {
      setIsGenerating(true);
      // Optimistically add user message
      setMessages(prev => [...prev, {
        id: Date.now().toString(),
        role: 'user',
        text,
        isFinal: true,
        timestamp: new Date()
      }]);

      sessionRef.current.sendRealtimeInput({
        content: [{ role: 'user', parts: [{ text }] }]
      });
    }
  }, [connectionState]);

  const disconnect = useCallback(() => {
    if (sessionRef.current) {
      try {
        sessionRef.current.close();
      } catch (e) {
        console.error("Error closing session", e);
      }
    }
    setConnectionState('disconnected');
    setMode('none');
    setIsGenerating(false);
    cleanup();
  }, []);

  const cleanup = () => {
    audioRecorderRef.current?.stop();
    audioStreamerRef.current?.stop();
    if (videoIntervalRef.current) {
      clearInterval(videoIntervalRef.current);
      videoIntervalRef.current = null;
    }
    sessionRef.current = null;
    setMessages([]);
    setIsMicOn(false);
    setIsGenerating(false);
  };

  useEffect(() => {
    return () => cleanup();
  }, []);

  return {
    connect,
    disconnect,
    sendVideoFrame,
    sendTextMessage,
    toggleMic,
    isMicOn,
    connectionState,
    mode,
    error,
    isVolumeHigh,
    messages,
    isGenerating
  };
}
