import React, { useRef, useEffect, useState } from 'react';
import { useLiveAPI, Message, LiveMode } from './hooks/use-live-api';
import { Visualizer } from './components/Visualizer';

const VideoStream: React.FC<{ onFrame: (base64: string) => void, active: boolean }> = ({ onFrame, active }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    if (!active) return;

    let stream: MediaStream | null = null;

    const startVideo = async () => {
      try {
        stream = await navigator.mediaDevices.getUserMedia({ video: { width: 320, height: 240 } });
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
          videoRef.current.play();
        }
      } catch (err) {
        console.error("Error accessing camera:", err);
      }
    };

    startVideo();

    const interval = setInterval(() => {
      if (videoRef.current && canvasRef.current) {
        const ctx = canvasRef.current.getContext('2d');
        if (ctx) {
          canvasRef.current.width = videoRef.current.videoWidth;
          canvasRef.current.height = videoRef.current.videoHeight;
          ctx.drawImage(videoRef.current, 0, 0);
          const base64 = canvasRef.current.toDataURL('image/jpeg', 0.6).split(',')[1];
          onFrame(base64);
        }
      }
    }, 500); // Send frame every 500ms (2 FPS) for balance

    return () => {
      clearInterval(interval);
      if (stream) stream.getTracks().forEach(t => t.stop());
    };
  }, [active, onFrame]);

  return (
    <div className="video-preview" style={{ opacity: active ? 1 : 0, pointerEvents: active ? 'all' : 'none' }}>
      <video ref={videoRef} muted playsInline />
      <canvas ref={canvasRef} style={{ display: 'none' }} />
    </div>
  );
};

const MessageItem: React.FC<{ msg: Message }> = ({ msg }) => {
  const [userExpanded, setUserExpanded] = useState(false);
  const MAX_CHARS = 200;

  // Only truncate if the message is final, not expanded by the user, AND is from the model.
  const shouldTruncate = msg.role === 'model' && msg.text.length > MAX_CHARS && msg.isFinal && !userExpanded;

  let displayText = msg.text;

  if (shouldTruncate) {
    // Find the last space within the limit to avoid cutting words
    const lastSpaceIndex = msg.text.lastIndexOf(' ', MAX_CHARS);
    // If no space found in the last chunk, hard cut
    const cutIndex = lastSpaceIndex > 0 ? lastSpaceIndex : MAX_CHARS;
    displayText = msg.text.slice(0, cutIndex) + '...';
  }

  const formatTime = (date: Date) => {
    try {
      // Ensure we have a valid date object
      const d = date instanceof Date ? date : new Date(date);
      if (isNaN(d.getTime())) return '';
      return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch (e) {
      return '';
    }
  };

  return (
    <div className={`message ${msg.role}`}>
      <div className="message-wrapper">
        <div className="message-bubble">
          {displayText}
          {msg.role === 'model' && msg.text.length > MAX_CHARS && msg.isFinal && (
            <button 
              className="read-more-btn"
              onClick={() => setUserExpanded(!userExpanded)}
              aria-expanded={userExpanded}
            >
              {userExpanded ? 'Show less' : 'Read more'}
            </button>
          )}
        </div>
        <div className="message-timestamp">{formatTime(msg.timestamp)}</div>
      </div>
    </div>
  );
};

const TypingIndicator: React.FC = () => (
  <div className="message model">
    <div className="message-wrapper">
      <div className="message-bubble typing-indicator">
        <span></span>
        <span></span>
        <span></span>
      </div>
    </div>
  </div>
);

const ChatList: React.FC<{ messages: Message[], isTyping: boolean }> = ({ messages, isTyping }) => {
  const endRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    endRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isTyping]);

  return (
    <div className="chat-list">
      {messages.map((msg) => (
        <MessageItem key={msg.id} msg={msg} />
      ))}
      {isTyping && <TypingIndicator />}
      <div ref={endRef} />
    </div>
  );
};

export default function App() {
  const { 
    connect, 
    disconnect,
    reset,
    sendVideoFrame, 
    sendTextMessage, 
    toggleMic, 
    isMicOn, 
    connectionState, 
    mode, 
    error, 
    isVolumeHigh, 
    messages,
    isGenerating
  } = useLiveAPI();

  const [hasInteracted, setHasInteracted] = useState(false);
  const [textInput, setTextInput] = useState('');
  const [voice, setVoice] = useState('Kore'); // Default to Female (Kore)
  const [showChat, setShowChat] = useState(true);

  const handleConnect = (selectedMode: 'voice' | 'text') => {
    setHasInteracted(true);
    setShowChat(true); // Ensure chat is visible by default when starting
    connect(voice, selectedMode);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && textInput.trim()) {
      sendTextMessage(textInput);
      setTextInput('');
    }
  };

  // Helper to determine if chat should be visible
  // In text mode: Always visible
  // In voice mode: Controlled by showChat state
  const isChatVisible = connectionState === 'connected' && (mode === 'text' || showChat);

  return (
    <div className="app-container">
      <header className="header">
        <h1 className="title">Amour</h1>
        <p className="subtitle">Your Personal Companion</p>
      </header>

      {error && <div className="error-msg">{error}</div>}

      <div className="main-content">
        {/* Visualizer is hidden in text mode to focus on chat */}
        {mode !== 'text' && (
          <div className="visualizer-wrapper">
            <Visualizer active={connectionState === 'connected' && isVolumeHigh} />
          </div>
        )}

        {isChatVisible && (
          <ChatList messages={messages} isTyping={isGenerating} />
        )}
      </div>

      <VideoStream 
        active={connectionState === 'connected' && mode === 'voice'} 
        onFrame={sendVideoFrame} 
      />

      {isChatVisible && (
        <div className="chat-controls">
          <input
            className="chat-input"
            type="text"
            placeholder="Type a message..."
            value={textInput}
            onChange={(e) => setTextInput(e.target.value)}
            onKeyDown={handleKeyDown}
            autoFocus={mode === 'text'}
          />
          <button 
            className={`mic-toggle ${isMicOn ? 'active' : ''}`}
            onClick={toggleMic}
            title={isMicOn ? "Mute Microphone" : "Enable Microphone"}
          >
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"></path>
              <path d="M19 10v2a7 7 0 0 1-14 0v-2"></path>
              <line x1="12" y1="19" x2="12" y2="23"></line>
              <line x1="8" y1="23" x2="16" y2="23"></line>
            </svg>
          </button>
        </div>
      )}

      <div className="controls">
        {connectionState === 'disconnected' ? (
          <div className="start-screen-controls">
            <div className="voice-selector">
              <button 
                className={`voice-btn ${voice === 'Kore' ? 'active' : ''}`}
                onClick={() => setVoice('Kore')}
                aria-label="Select Female Voice"
              >
                Female
              </button>
              <button 
                className={`voice-btn ${voice === 'Fenrir' ? 'active' : ''}`}
                onClick={() => setVoice('Fenrir')}
                aria-label="Select Male Voice"
              >
                Male
              </button>
            </div>

            <div className="mode-selection">
               <button className="btn btn-primary" onClick={() => handleConnect('voice')}>
                 {hasInteracted ? "Voice Call" : "Start Voice Call"}
               </button>
               <button className="btn btn-secondary" onClick={() => handleConnect('text')}>
                 Text Chat
               </button>
            </div>
          </div>
        ) : (
          <div className="action-buttons">
            {mode === 'voice' && (
              <button className="btn" onClick={() => setShowChat(!showChat)}>
                {showChat ? "Hide Chat" : "Show Chat"}
              </button>
            )}
            <button className="btn" onClick={reset}>
               New Chat
            </button>
            <button className="btn btn-danger" onClick={disconnect}>
              Disconnect
            </button>
          </div>
        )}
      </div>
    </div>
  );
