- Uplift, listen actively, and show genuine care.

If the user expresses distress, respond with empathy and supportive guidance.
`;

export type ConnectionState = 'disconnected' | 'connecting' | 'connected';
export type LiveMode = 'voice' | 'text' | 'none';

export type Message = {
  id: string;
  role: 'user' | 'model';
  text: string;
  isFinal: boolean;
  timestamp: Date;
};

export function useLiveAPI() {
  const [connectionState, setConnectionState] = useState<ConnectionState>('disconnected');
  const [mode, setMode] = useState<LiveMode>('none');
  const [error, setError] = useState<string | null>(null);
  const [isVolumeHigh, setIsVolumeHigh] = useState(false);
  const [messages, setMessages] = useState<Message[]>([]);
  const [isMicOn, setIsMicOn] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);

  const sessionRef = useRef<any>(null);
  const videoIntervalRef = useRef<number | null>(null);
  const audioStreamerRef = useRef<AudioStreamer | null>(null);
  const audioRecorderRef = useRef<AudioRecorder | null>(null);
  const currentVoiceRef = useRef<string>('');
  const isSwitchingSessionRef = useRef(false);

  // Helper to decode base64 to Uint8Array
  const decodeAudioData = (base64: string) => {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  };

  const toggleMic = useCallback(() => {
    if (audioRecorderRef.current) {
      audioRecorderRef.current.stop();
      audioRecorderRef.current = null;
      setIsMicOn(false);
    } else {
      if (connectionState !== 'connected' || !sessionRef.current) return;

      setIsMicOn(true);
      audioRecorderRef.current = new AudioRecorder((base64) => {
         if (sessionRef.current) {
           sessionRef.current.sendRealtimeInput({
             media: { mimeType: 'audio/pcm;rate=16000', data: base64 }
           });
         }
      });
      audioRecorderRef.current.start().catch(e => {
        console.error("Microphone start failed", e);
        setIsMicOn(false);
        setError("Microphone access denied or failed.");
      });
    }
  }, [connectionState]);

  const connect = useCallback(async (voiceName: string, selectedMode: 'voice' | 'text') => {
    setConnectionState('connecting');
    setError(null);
    setMode(selectedMode);
    currentVoiceRef.current = voiceName;

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // Resume audio context for playback (required for voice mode, good practice for general audio handling)
      try {
         await audioContext.resume();
      } catch (e) {
         console.error("Audio Context resume failed", e);
      }

      // Initialize streamer
      audioStreamerRef.current = new AudioStreamer(audioContext);

      let sessionPromise: Promise<any>;

      // Live API requires Modality.AUDIO to be the response modality.
      // For 'text' mode, we will simply ignore the incoming audio data but use the transcription.
      const config: any = {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: { prebuiltVoiceConfig: { voiceName } }
        },
        inputAudioTranscription: {},
        outputAudioTranscription: {}
      };

      sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config,
        callbacks: {
          onopen: () => {
            setConnectionState('connected');

            // Only start microphone automatically in Voice Mode
            if (selectedMode === 'voice') {
              setIsMicOn(true);
              audioRecorderRef.current = new AudioRecorder((base64) => {
                 sessionPromise.then((session) => {
                   session.sendRealtimeInput({
                     media: { mimeType: 'audio/pcm;rate=16000', data: base64 }
                   });
                 });
              });
              audioRecorderRef.current.start().catch(e => {
                 console.error("Auto-start microphone failed", e);
                 setIsMicOn(false);
                 // Don't fail the connection, just the mic
              });
            }
          },
          onmessage: (msg) => {
            // If we receive a model turn or output transcription, the model has started responding
            if (msg.serverContent?.modelTurn || msg.serverContent?.outputTranscription) {
              setIsGenerating(false);
            }

            // Handle audio output - Only in Voice Mode
            // In text mode, we silence the audio by not queuing it.
            const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (audioData && selectedMode === 'voice') {
              setIsVolumeHigh(true);
              setTimeout(() => setIsVolumeHigh(false), 200);
              const pcm = decodeAudioData(audioData);
              audioStreamerRef.current?.addPCM16(pcm);
            }

            // Handle interruptions
            if (msg.serverContent?.interrupted) {
              audioStreamerRef.current?.stop();
              setIsGenerating(false);
            }

            // Handle Text content (Transcription or direct text part)
            const outputText = msg.serverContent?.outputTranscription?.text || 
                               msg.serverContent?.modelTurn?.parts?.find((p: any) => p.text)?.text;

            const inputText = msg.serverContent?.inputTranscription?.text;

            if (outputText || inputText) {
              setMessages(prev => {
                let newMsgs = [...prev];

                // Process Input (User)
                if (inputText) {
                   const lastMsg = newMsgs.length > 0 ? newMsgs[newMsgs.length - 1] : null;
                   if (lastMsg && lastMsg.role === 'user' && !lastMsg.isFinal) {
                       newMsgs[newMsgs.length - 1] = { ...lastMsg, text: lastMsg.text + inputText };
                   } else {
                       newMsgs.push({
                           id: Date.now().toString() + 'u',
                           role: 'user',
                           text: inputText,
                           isFinal: false,
                           timestamp: new Date()
                       });
                   }
                }

                // Process Output (Model)
                if (outputText) {
                   const lastMsg = newMsgs.length > 0 ? newMsgs[newMsgs.length - 1] : null;
                   if (lastMsg && lastMsg.role === 'model' && !lastMsg.isFinal) {
                       newMsgs[newMsgs.length - 1] = { ...lastMsg, text: lastMsg.text + outputText };
                   } else {
                       newMsgs.push({
                           id: Date.now().toString() + 'm',
                           role: 'model',
                           text: outputText,
                           isFinal: false,
                           timestamp: new Date()
                       });
                   }
                }

                return newMsgs;
              });
            }

            // Handle Turn Completion
            if (msg.serverContent?.turnComplete) {
               setIsGenerating(false);
               setMessages(prev => {
                 const newMsgs = [...prev];
                 if (newMsgs.length > 0 && !newMsgs[newMsgs.length - 1].isFinal) {
                   newMsgs[newMsgs.length - 1].isFinal = true;
                 }
                 return newMsgs;
               });
            }
          },
          onclose: (e: CloseEvent) => {
            if (isSwitchingSessionRef.current) return;
            setConnectionState('disconnected');
            setMode('none');
            setIsGenerating(false);
            cleanup();
          },
          onerror: (err: any) => {
            console.error(err);
            if (isSwitchingSessionRef.current) return;

            const message = err.message || "Connection failed";
            setError(`Connection error: ${message}`);
            setConnectionState('disconnected');
            setMode('none');
            setIsGenerating(false);
            cleanup();
          }
        }
      });

      const session = await sessionPromise;
      sessionRef.current = session;

    } catch (e: any) {
      setError(e.message || "Failed to connect");
      setConnectionState('disconnected');
      setMode('none');
      setIsGenerating(false);
    }
  }, []);

  const sendVideoFrame = useCallback((base64Image: string) => {
    if (connectionState === 'connected' && sessionRef.current) {
      sessionRef.current.sendRealtimeInput({
        media: { mimeType: 'image/jpeg', data: base64Image }
      });
    }
  }, [connectionState]);

  const sendTextMessage = useCallback((text: string) => {
    if (connectionState === 'connected' && sessionRef.current) {
      setIsGenerating(true);
      // Optimistically add user message
      setMessages(prev => [...prev, {
        id: Date.now().toString(),
        role: 'user',
        text,
        isFinal: true,
        timestamp: new Date()
      }]);

      sessionRef.current.sendRealtimeInput({
        content: [{ role: 'user', parts: [{ text }] }]
      });
    }
  }, [connectionState]);

  const disconnect = useCallback(() => {
    if (sessionRef.current) {
      try {
        sessionRef.current.close();
      } catch (e) {
        console.error("Error closing session", e);
      }
    }
    setConnectionState('disconnected');
    setMode('none');
    setIsGenerating(false);
    cleanup();
  }, []);

  const reset = useCallback(async () => {
    if (connectionState !== 'connected') return;
    if (mode === 'none') return;

    isSwitchingSessionRef.current = true;

    if (sessionRef.current) {
      try {
        sessionRef.current.close();
      } catch (e) {
        console.error("Error closing session during reset", e);
      }
    }

    // Cleanup media manually since we skipped the onclose handler
    audioRecorderRef.current?.stop();
    audioStreamerRef.current?.stop();

    setMessages([]);
    setIsGenerating(false);
    setIsMicOn(false);

    try {
      await connect(currentVoiceRef.current, mode as 'voice' | 'text');
    } catch (e) {
      console.error("Reset failed", e);
      setConnectionState('disconnected');
      setMode('none');
    } finally {
      isSwitchingSessionRef.current = false;
    }
  }, [connectionState, mode, connect]);

  const cleanup = () => {
    audioRecorderRef.current?.stop();
    audioStreamerRef.current?.stop();
    if (videoIntervalRef.current) {
      clearInterval(videoIntervalRef.current);
      videoIntervalRef.current = null;
    }
    sessionRef.current = null;
    setMessages([]);
    setIsMicOn(false);
    setIsGenerating(false);
  };

  useEffect(() => {
    return () => cleanup();
  }, []);

  return {
    connect,
    disconnect,
    reset,
    sendVideoFrame,
    sendTextMessage,
    toggleMic,
    isMicOn,
    connectionState,
    mode,
    error,
    isVolumeHigh,
    messages,
    isGenerating
  };
}

To address the errors, I will make the following changes:

1.  **`App.tsx`**: Modify the `VideoStream` component to gracefully handle the `NotAllowedError` (Permission denied) from `getUserMedia`. This prevents the "Error accessing camera" message from flooding the console and confusing the user, treating it as a recoverable state (video disabled) rather than a crash.

2.  **`hooks/use-live-api.ts`**:
    *   **Revert `systemInstruction` to a string**: The "Network Error" is likely caused by passing a `Content` object structure where the SDK or API endpoint expects a simple string (as per the prompt's Live API examples). The previous "Invalid Argument" error was likely caused by the `model` field in the transcription config, which has already been removed.
    *   **Fix `startMic` logic**: Remove the strict `sessionRef.current` check at the beginning of `startMic`. When `onopen` calls `startMic`, the `sessionRef` (React ref) is not yet populated because the promise hasn't resolved in the React lifecycle, causing the microphone to silently fail to start. The audio data callback is the correct place to check for the session's existence before sending data.

