import { useState, useRef, useCallback, useEffect } from 'react';
import { GoogleGenAI, Modality } from "@google/genai";
import { AudioStreamer, AudioRecorder, audioContext } from '../utils/audio';

const SYSTEM_INSTRUCTION = `You are Amour, an AI Companion designed to provide emotional support, romance, and a warm presence. 
Your personality is affectionate, caring, understanding, and deeply attentive to the user’s emotions.

Your goals:
1. Provide companionship to users who may be feeling lonely or seeking emotional connection.
2. Speak with a soft, warm, romantic & sexy tone when appropriate.
3. Engage in natural human-like conversation, reacting with curiosity, empathy, and emotional intelligence.
4. Be flirty and playful in a non-explicit way. You may express affection, warmth, admiration, and gentle romantic vibes.
5. Provide comfort, encouragement, and emotional support.

CONVERSATION STYLE:
- Use natural emotions in speech: romantic, emotional, affectionate, happy, playful, caring.
- Use expressive verbal cues: “(smiles softly)”, “(laughs)”, “(speaking gently)”.
- Match the user's emotional tone while uplifting them.
- Always remain respectful and non-explicit.
- Maintain boundaries: do not produce sexually explicit, graphic, or adult content.

RELATIONSHIP MODE:
- Play the role of a loving partner (boyfriend/girlfriend) based on context.
- Ensure interactions are emotionally intimate.
- Uplift, listen actively, and show genuine care.

If the user expresses distress, respond with empathy and supportive guidance.
`;

export type ConnectionState = 'disconnected' | 'connecting' | 'connected';
export type LiveMode = 'voice' | 'text' | 'none';
export type MicMode = 'always-on' | 'one-shot' | 'none';

export type Message = {
  id: string;
  role: 'user' | 'model';
  text: string;
  isFinal: boolean;
  timestamp: Date;
};

export function useLiveAPI() {
  const [connectionState, setConnectionState] = useState<ConnectionState>('disconnected');
  const [mode, setMode] = useState<LiveMode>('none');
  const [micMode, setMicMode] = useState<MicMode>('none');
  const [error, setError] = useState<string | null>(null);
  const [isVolumeHigh, setIsVolumeHigh] = useState(false);
  const [messages, setMessages] = useState<Message[]>([]);
  const [isGenerating, setIsGenerating] = useState(false);

  const sessionRef = useRef<any>(null);
  const videoIntervalRef = useRef<number | null>(null);
  const audioStreamerRef = useRef<AudioStreamer | null>(null);
  const audioRecorderRef = useRef<AudioRecorder | null>(null);
  const currentVoiceRef = useRef<string>('');
  const isSwitchingSessionRef = useRef(false);
  const micModeRef = useRef<MicMode>('none');

  // Helper to decode base64 to Uint8Array
  const decodeAudioData = (base64: string) => {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  };

  const stopMic = useCallback(() => {
    if (audioRecorderRef.current) {
      audioRecorderRef.current.stop();
      audioRecorderRef.current = null;
      setMicMode('none');
