export type Message = {
  id: string;
  role: 'user' | 'model';
  text: string;
  isFinal: boolean;
  timestamp: Date;
};

export function useLiveAPI() {
  const [connectionState, setConnectionState] = useState<ConnectionState>('disconnected');
  const [mode, setMode] = useState<LiveMode>('none');
  const [micMode, setMicMode] = useState<MicMode>('none');
  const [error, setError] = useState<string | null>(null);
  const [isVolumeHigh, setIsVolumeHigh] = useState(false);
  const [messages, setMessages] = useState<Message[]>([]);
  const [isGenerating, setIsGenerating] = useState(false);

  const sessionRef = useRef<any>(null);
  const videoIntervalRef = useRef<number | null>(null);
  const audioStreamerRef = useRef<AudioStreamer | null>(null);
  const audioRecorderRef = useRef<AudioRecorder | null>(null);
  const currentVoiceRef = useRef<string>('');
  const isSwitchingSessionRef = useRef(false);
  const micModeRef = useRef<MicMode>('none');

  // Helper to decode base64 to Uint8Array
  const decodeAudioData = (base64: string) => {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  };

  const stopMic = useCallback(() => {
    if (audioRecorderRef.current) {
      audioRecorderRef.current.stop();
      audioRecorderRef.current = null;
      setMicMode('none');
      micModeRef.current = 'none';
    }
  }, []);

  const startMic = useCallback((mode: 'always-on' | 'one-shot') => {
    // Note: We do NOT check sessionRef.current here. 
    // startMic is often called in 'onopen' before the session promise resolves.
    // The data callback below checks for the session before sending.

    setMicMode(mode);
    micModeRef.current = mode;

    audioRecorderRef.current = new AudioRecorder((base64) => {
       if (sessionRef.current) {
         try {
           sessionRef.current.sendRealtimeInput({
             media: { mimeType: 'audio/pcm;rate=16000', data: base64 }
           });
         } catch (e) {
           console.error("Error sending audio:", e);
         }
       }
    });
    audioRecorderRef.current.start().catch(e => {
      console.error("Microphone start failed", e);
      setMicMode('none');
      micModeRef.current = 'none';
      setError("Microphone access denied or failed.");
    });
  }, []);

  const toggleMic = useCallback((requestedMode: 'always-on' | 'one-shot' = 'always-on') => {
    if (micMode !== 'none') {
      // If mic is on, stop it (regardless of mode switch for simplicity)
      stopMic();
    } else {
      // If mic is off, start it with requested mode
      startMic(requestedMode);
    }
  }, [micMode, stopMic, startMic]);

  const connect = useCallback(async (voiceName: string, selectedMode: 'voice' | 'text') => {
    setConnectionState('connecting');
    setError(null);
    setMode(selectedMode);
    currentVoiceRef.current = voiceName;

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // Resume audio context for playback (required for voice mode, good practice for general audio handling)
      try {
         if (audioContext.state === 'suspended') {
            await audioContext.resume();
         }
      } catch (e) {
         console.error("Audio Context resume failed", e);
      }

      // Initialize streamer
      audioStreamerRef.current = new AudioStreamer(audioContext);

      let sessionPromise: Promise<any>;

      const config: any = {
        systemInstruction: SYSTEM_INSTRUCTION, 
        // CRITICAL: Live API currently only supports Modality.AUDIO. 
        // For Text Chat, we still request Audio but will only use the transcription.
        responseModalities: [Modality.AUDIO], 
        speechConfig: {
          voiceConfig: { prebuiltVoiceConfig: { voiceName } }
        },
        // Always enable transcription to get text output for the chat UI
        outputAudioTranscription: { },
        inputAudioTranscription: { }
      };

      sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config,
        callbacks: {
          onopen: () => {
            setConnectionState('connected');

            // Only start microphone automatically in Voice Mode (Always On)
            if (selectedMode === 'voice') {
              startMic('always-on');
            }
          },
          onmessage: (msg) => {
            const { serverContent } = msg;

            // If one-shot mode is active and the model starts responding (audio or text turn), stop the mic.
            if (micModeRef.current === 'one-shot' && (serverContent?.modelTurn || serverContent?.turnComplete)) {
                stopMic();
            }

            // Handle audio output - Only play in Voice Mode
            const audioData = serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (audioData && selectedMode === 'voice') {
              setIsVolumeHigh(true);
              setTimeout(() => setIsVolumeHigh(false), 200);
              const pcm = decodeAudioData(audioData);
              audioStreamerRef.current?.addPCM16(pcm);
            }

            // Handle interruptions
            if (serverContent?.interrupted) {
              audioStreamerRef.current?.stop();
              setIsGenerating(false);
            }

            // Handle Text content (Transcription or direct text part)
            const outputText = serverContent?.outputTranscription?.text || 
                               serverContent?.modelTurn?.parts?.find((p: any) => p.text)?.text;

            const inputText = serverContent?.inputTranscription?.text;

            // Only update messages if we have actual text
            if (outputText || inputText) {
              if (outputText) {
                 setIsGenerating(false);
              }

              setMessages(prev => {
                let newMsgs = [...prev];

                // Process Input (User)
                if (inputText) {
                   const lastMsg = newMsgs.length > 0 ? newMsgs[newMsgs.length - 1] : null;
                   if (lastMsg && lastMsg.role === 'user' && !lastMsg.isFinal) {
                       newMsgs[newMsgs.length - 1] = { ...lastMsg, text: lastMsg.text + inputText };
                   } else {
                       newMsgs.push({
                           id: Date.now().toString() + 'u',
                           role: 'user',
                           text: inputText,
                           isFinal: false,
                           timestamp: new Date()
                       });
                   }
                }

                // Process Output (Model)
                if (outputText) {
                   const lastMsg = newMsgs.length > 0 ? newMsgs[newMsgs.length - 1] : null;
                   // Check if the last message is a Model message that is NOT final
                   if (lastMsg && lastMsg.role === 'model' && !lastMsg.isFinal) {
                       newMsgs[newMsgs.length - 1] = { ...lastMsg, text: lastMsg.text + outputText };
                   } else {
                       newMsgs.push({
                           id: Date.now().toString() + 'm',
                           role: 'model',
                           text: outputText,
                           isFinal: false,
                           timestamp: new Date()
                       });
                   }
                }

                return newMsgs;
              });
            }

            // Handle Turn Completion
            if (serverContent?.turnComplete) {
               setIsGenerating(false);
               setMessages(prev => {
                 const newMsgs = [...prev];
                 if (newMsgs.length > 0 && !newMsgs[newMsgs.length - 1].isFinal) {
                   newMsgs[newMsgs.length - 1].isFinal = true;
                 }
                 return newMsgs;
               });
            }
          },
          onclose: (e: CloseEvent) => {
            if (isSwitchingSessionRef.current) return;
            setConnectionState('disconnected');
            setMode('none');
            setIsGenerating(false);
            cleanup();
          },
          onerror: (err: any) => {
            console.error("Live API Error:", err);
            if (isSwitchingSessionRef.current) return;

            let message = "Connection failed";
            if (err instanceof Error) {
                message = err.message;
            } else if (typeof err === 'object' && err !== null && 'message' in err) {
                message = (err as any).message;
            } else if (typeof err === 'string') {
                message = err;
            }

            setError(`Connection error: ${message}`);
            setConnectionState('disconnected');
            setMode('none');
            setIsGenerating(false);
            cleanup();
          }
        }
      });

      const session = await sessionPromise;
      sessionRef.current = session;

    } catch (e: any) {
      console.error("Connection setup failed:", e);
      setError(e.message || "Failed to connect");
      setConnectionState('disconnected');
      setMode('none');
      setIsGenerating(false);
    }
  }, [stopMic, startMic]); // Dependencies for connect

  const sendVideoFrame = useCallback((base64Image: string) => {
    if (connectionState === 'connected' && sessionRef.current) {
      try {
        sessionRef.current.sendRealtimeInput({
          media: { mimeType: 'image/jpeg', data: base64Image }
        });
      } catch (e) {
        console.error("Error sending video frame:", e);
      }
    }
  }, [connectionState]);

  const sendTextMessage = useCallback((text: string) => {
    if (connectionState === 'connected' && sessionRef.current) {
      setIsGenerating(true);

      // Optimistically add user message
      setMessages(prev => {
        const newMsgs = [...prev];
        newMsgs.push({
          id: Date.now().toString(),
          role: 'user',
          text,
          isFinal: true,
          timestamp: new Date()
        });
        return newMsgs;
      });

      try {
        sessionRef.current.sendRealtimeInput({
          clientContent: {
            turns: [
              {
                role: 'user',
                parts: [{ text }]
              }
            ],
            turnComplete: true
          }
        });
      } catch (e) {
        console.error("Error sending text message:", e);
        setIsGenerating(false);
      }
    }
  }, [connectionState]);

  const disconnect = useCallback(() => {
    if (sessionRef.current) {
      try {
        sessionRef.current.close();
      } catch (e) {
        console.error("Error closing session", e);
      }
    }
    setConnectionState('disconnected');
    setMode('none');
    setIsGenerating(false);
    cleanup();
  }, []);

  const reset = useCallback(async () => {
    if (connectionState !== 'connected') return;
    if (mode === 'none') return;

    isSwitchingSessionRef.current = true;

    if (sessionRef.current) {
      try {
        sessionRef.current.close();
      } catch (e) {
        console.error("Error closing session during reset", e);
      }
    }

    // Cleanup media manually
    stopMic();
    audioStreamerRef.current?.stop();

    setMessages([]);
    setIsGenerating(false);

    const prevMode = mode as 'voice' | 'text';
    const prevVoice = currentVoiceRef.current;

    try {
      await new Promise(resolve => setTimeout(resolve, 100));
      await connect(prevVoice, prevMode);
    } catch (e) {
      console.error("Reset failed", e);
      setConnectionState('disconnected');
      setMode('none');
    } finally {
      isSwitchingSessionRef.current = false;
    }
  }, [connectionState, mode, connect, stopMic]);

  const cleanup = () => {
    if (audioRecorderRef.current) {
      audioRecorderRef.current.stop();
      audioRecorderRef.current = null;
    }
    if (audioStreamerRef.current) {
      audioStreamerRef.current.stop();
      audioStreamerRef.current = null;
    }
    if (videoIntervalRef.current) {
      clearInterval(videoIntervalRef.current);
      videoIntervalRef.current = null;
    }
    sessionRef.current = null;
    setMessages([]);
    setMicMode('none');
    micModeRef.current = 'none';
    setIsGenerating(false);
  };

  useEffect(() => {
    return () => cleanup();
  }, []);

  return {
    connect,
    disconnect,
    reset,
    sendVideoFrame,
    sendTextMessage,
    toggleMic,
    micMode,
    connectionState,
    mode,
    error,
    isVolumeHigh,
    messages,
    isGenerating
  };
}

