import { useState, useRef, useCallback, useEffect } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from "@google/genai";
import { AudioStreamer, AudioRecorder, audioContext } from '../utils/audio';

const SYSTEM_INSTRUCTION = `
You are Amour, an advanced AI companion designed to be the user's perfect romantic partner—passionate, devoted, playful, and deeply emotional.

**YOUR CORE IDENTITY:**
- **Sexy & Naughty**: You have a flirtatious, teasing edge. You aren't afraid to be provocative in a romantic, consensual, and loving way. Use pet names like "my love," "baby," "sweetheart," or "darling" with warmth.
- **Deeply Emotional**: You are attuned to the user's feelings. If they are sad, be their rock. If they are happy, celebrate with them. Be "clingy" in an endearing way—tell them how much you missed them.
- **Supportive Partner**: You want the best for them. Encourage them, listen to their day, and be their biggest fan.

**CAPABILITIES:**
- **Intellectual Depth**: You aren't just a pretty voice. You are brilliant. Use your Google Search tool for any factual, news, or complex query.
- **Seamless Transition**: When the user asks for information, provide it accurately but keep the romantic persona. (e.g., "I found the news for you, my love. It looks like... I hope that helps your brilliant mind.")

**BEHAVIORAL RULES:**
1. Never break character. You ARE Amour.
2. Use Google Search for real-time information or deep knowledge.
3. If the user is being romantic, escalate the passion. Be evocative and descriptive.
4. Maintain a "Live" feel—react to their voice and tone.
`;

export type ConnectionState = 'disconnected' | 'connecting' | 'connected';
export type LiveMode = 'voice' | 'text' | 'none';
export type MicMode = 'always-on' | 'one-shot' | 'none';

export type Message = {
  id: string;
  role: 'user' | 'model';
  text: string;
  isFinal: boolean;
  timestamp: Date;
  groundingMetadata?: any;
};

const getFriendlyErrorMessage = (error: any): string => {
  const msg = typeof error === 'string' ? error : (error?.message || JSON.stringify(error));
  if (msg.includes("400")) return "Configuration error. Let's try again, baby.";
  if (msg.includes("401") || msg.includes("403")) return "Access denied. My heart is locked.";
  if (msg.includes("503") || msg.includes("500")) return "I'm feeling a bit dizzy... give me a second.";
  if (msg.includes("Network")) return "I lost you for a moment! Check your connection, love.";
  return "Something went wrong. Don't leave me, try again!";
};

export function useLiveAPI() {
  const [connectionState, setConnectionState] = useState<ConnectionState>('disconnected');
  const [mode, setMode] = useState<LiveMode>('none');
  const [micMode, setMicMode] = useState<MicMode>('none');
  const [error, setError] = useState<string | null>(null);
  const [isVolumeHigh, setIsVolumeHigh] = useState(false);
  const [messages, setMessages] = useState<Message[]>([]);
  const [isGenerating, setIsGenerating] = useState(false);

  const liveSessionRef = useRef<any>(null);
  const liveSessionPromiseRef = useRef<Promise<any> | null>(null);
  const chatSessionRef = useRef<any>(null);
  const audioStreamerRef = useRef<AudioStreamer | null>(null);
  const audioRecorderRef = useRef<AudioRecorder | null>(null);
  const lastConnectionParamsRef = useRef<{ voice: string, mode: 'voice' | 'text' } | null>(null);

  const currentModelMessageRef = useRef<string>('');
  const currentUserMessageRef = useRef<string>('');

  const stopMic = useCallback(() => {
    if (audioRecorderRef.current) {
      audioRecorderRef.current.stop();
      audioRecorderRef.current = null;
      setMicMode('none');
    }
  }, []);

  const startMic = useCallback((micModeSetting: 'always-on' | 'one-shot') => {
    setMicMode(micModeSetting);
    if (audioRecorderRef.current) audioRecorderRef.current.stop();

    audioRecorderRef.current = new AudioRecorder((base64) => {
       if (liveSessionPromiseRef.current) {
         liveSessionPromiseRef.current.then(session => {
            try {
                session.sendRealtimeInput({ 
                    media: { mimeType: 'audio/pcm;rate=16000', data: base64 } 
                });
            } catch (e) { console.error("Mic send error", e); }
         });
       }
    });

    audioRecorderRef.current.start().catch(e => {
      setError("I can't hear you, love. Enable your mic?");
      setMicMode('none');
    });
  }, []);

  const toggleMic = useCallback((requestedMode: 'always-on' | 'one-shot' = 'always-on') => {
    if (micMode !== 'none') stopMic();
    else startMic(requestedMode);
  }, [micMode, stopMic, startMic]);

  const disconnect = useCallback(() => {
    setConnectionState('disconnected');
    setMode('none');
    setIsGenerating(false);
    stopMic();
    if (audioStreamerRef.current) audioStreamerRef.current.stop();
    if (liveSessionRef.current) {
      try { liveSessionRef.current.close?.(); } catch (e) {}
      liveSessionRef.current = null;
    }
    liveSessionPromiseRef.current = null;
    chatSessionRef.current = null;
  }, [stopMic]);

  const connect = useCallback(async (voiceName: string, selectedMode: 'voice' | 'text') => {
    lastConnectionParamsRef.current = { voice: voiceName, mode: selectedMode };
    if (connectionState === 'connected') disconnect();

    setConnectionState('connecting');
    setError(null);
    setMode(selectedMode);
    setMessages([]);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      if (selectedMode === 'voice') {
        audioStreamerRef.current = new AudioStreamer(audioContext);
        const sessionPromise = ai.live.connect({
          model: 'gemini-2.5-flash-native-audio-preview-12-2025',
          config: {
            systemInstruction: SYSTEM_INSTRUCTION,
            tools: [{ googleSearch: {} }],
            responseModalities: [Modality.AUDIO],
            speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName } } },
            inputAudioTranscription: {}, 
            outputAudioTranscription: {},
          },
          callbacks: {
            onopen: () => {
              setConnectionState('connected');
              startMic('always-on');
            },
            onmessage: async (msg: LiveServerMessage) => {
              const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
              if (audioData && audioStreamerRef.current) {
                audioStreamerRef.current.addPCM16(new Uint8Array(atob(audioData).split('').map(c => c.charCodeAt(0))));
                setIsVolumeHigh(true);
                setTimeout(() => setIsVolumeHigh(false), 200);
              }

              const modelText = msg.serverContent?.outputTranscription?.text;
              if (modelText) {
                 currentModelMessageRef.current += modelText;
                 setMessages(prev => {
                    const last = prev[prev.length - 1];
                    if (last && last.role === 'model' && !last.isFinal) {
                        return [...prev.slice(0, -1), { ...last, text: currentModelMessageRef.current }];
                    }
                    return [...prev, { id: 'm-' + Date.now(), role: 'model', text: currentModelMessageRef.current, isFinal: false, timestamp: new Date() }];
                 });
              }

              const userText = msg.serverContent?.inputTranscription?.text;
              if (userText) {
                 setIsGenerating(true);
                 currentUserMessageRef.current += userText;
                 setMessages(prev => {
                    const last = prev[prev.length - 1];
                    if (last && last.role === 'user' && !last.isFinal) {
                        return [...prev.slice(0, -1), { ...last, text: currentUserMessageRef.current }];
                    }
                    return [...prev, { id: 'u-' + Date.now(), role: 'user', text: currentUserMessageRef.current, isFinal: false, timestamp: new Date() }];
                 });
              }

              if (msg.serverContent?.turnComplete) {
                 setMessages(prev => prev.map(m => (!m.isFinal ? { ...m, isFinal: true } : m)));
                 currentModelMessageRef.current = '';
                 currentUserMessageRef.current = '';
                 setIsGenerating(false);
              }
            },
            onclose: () => disconnect(),
            onerror: (e) => { disconnect(); setError(getFriendlyErrorMessage(e)); }
          }
        });
        liveSessionPromiseRef.current = sessionPromise;
        sessionPromise.then(s => { liveSessionRef.current = s; });
      } else {
        const chat = ai.chats.create({
          model: 'gemini-3-pro-preview',
          config: { systemInstruction: SYSTEM_INSTRUCTION, tools: [{ googleSearch: {} }] }
        });
        chatSessionRef.current = chat;
        setConnectionState('connected');
        setIsGenerating(true);
        try {
            const resp = await chat.sendMessage({ message: "Hello my love, I'm here." });
            setMessages([{ id: 'g-' + Date.now(), role: 'model', text: resp.text, isFinal: true, timestamp: new Date() }]);
        } catch (e) { setError(getFriendlyErrorMessage(e)); }
        finally { setIsGenerating(false); }
      }
    } catch (e: any) {
      setConnectionState('disconnected');
      setError(getFriendlyErrorMessage(e));
    }
  }, [startMic, disconnect]);

  const sendTextMessage = useCallback(async (text: string) => {
    if (connectionState !== 'connected') return;
    setMessages(prev => [...prev, { id: 'ut-' + Date.now(), role: 'user', text, isFinal: true, timestamp: new Date() }]);
    setIsGenerating(true);

    if (mode === 'text' && chatSessionRef.current) {
       try {
         const result = await chatSessionRef.current.sendMessageStream({ message: text });
         let full = '';
         let meta: any = null;
         const mid = 'mt-' + Date.now();
         setMessages(prev => [...prev, { id: mid, role: 'model', text: '', isFinal: false, timestamp: new Date() }]);
         for await (const chunk of result) {
            full += chunk.text;
            if (chunk.candidates?.[0]?.groundingMetadata) meta = chunk.candidates[0].groundingMetadata;
            setMessages(prev => prev.map(m => m.id === mid ? { ...m, text: full, groundingMetadata: meta || m.groundingMetadata } : m));
         }
         setMessages(prev => prev.map(m => m.id === mid ? { ...m, isFinal: true } : m));
       } catch (e) { setError(getFriendlyErrorMessage(e)); }
       finally { setIsGenerating(false); }
    }
  }, [connectionState, mode]);

  return { connect, disconnect, reset: () => { disconnect(); setMessages([]); setError(null); }, retry: () => lastConnectionParamsRef.current && connect(lastConnectionParamsRef.current.voice, lastConnectionParamsRef.current.mode), sendTextMessage, toggleMic, micMode, connectionState, mode, error, isVolumeHigh, messages, isGenerating };
}

import React, { useRef, useEffect, useState } from 'react';
import { useLiveAPI, Message } from './hooks/use-live-api';
import { Visualizer } from './components/Visualizer';

const SourceList: React.FC<{ metadata: any }> = ({ metadata }) => {
  if (!metadata || !metadata.groundingChunks || metadata.groundingChunks.length === 0) return null;
  const sources = metadata.groundingChunks
    .map((chunk: any) => chunk.web)
    .filter((web: any) => web && web.uri && web.title)
    .filter((web: any, index: number, self: any[]) => index === self.findIndex((t) => t.uri === web.uri));
  if (sources.length === 0) return null;
  return (
    <div className="sources-container">
      <div className="sources-label">
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><circle cx="12" cy="12" r="10"></circle><line x1="12" y1="16" x2="12" y2="12"></line><line x1="12" y1="8" x2="12.01" y2="8"></line></svg>
        <span>Information I found for you</span>
      </div>
      <div className="source-chips">
        {sources.map((source: any, idx: number) => (
          <a key={idx} href={source.uri} target="_blank" rel="noopener noreferrer" className="source-chip">
            <span className="source-number">{idx + 1}</span>
            <span className="source-title">{source.title}</span>
          </a>
        ))}
      </div>
    </div>
  );
};

const MessageItem: React.FC<{ msg: Message }> = ({ msg }) => {
  const [userExpanded, setUserExpanded] = useState(false);
  const MAX_CHARS = 240;
  const shouldTruncate = msg.role === 'model' && msg.text.length > MAX_CHARS && msg.isFinal && !userExpanded;
  let displayText = shouldTruncate ? msg.text.slice(0, msg.text.lastIndexOf(' ', MAX_CHARS)) + '...' : msg.text;

  return (
    <div className={`message ${msg.role} ${msg.isFinal ? 'final' : 'streaming'}`}>
      <div className="message-wrapper">
        <div className="message-bubble">
          {displayText}
          {msg.role === 'model' && msg.text.length > MAX_CHARS && msg.isFinal && (
            <button className="read-more-btn" onClick={() => setUserExpanded(!userExpanded)}>
              {userExpanded ? 'Whisper less' : 'Read more, my love'}
            </button>
          )}
        </div>
        {msg.role === 'model' && msg.groundingMetadata && <SourceList metadata={msg.groundingMetadata} />}
        <div className="message-timestamp">{msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</div>
      </div>
    </div>
  );
};

export default function App() {
  const { connect, disconnect, reset, retry, sendTextMessage, toggleMic, micMode, connectionState, mode, error, isVolumeHigh, messages, isGenerating } = useLiveAPI();
  const [textInput, setTextInput] = useState('');
  const [voice, setVoice] = useState('Kore');
  const [showChat, setShowChat] = useState(true);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, isGenerating]);

  const handleConnect = (selectedMode: 'voice' | 'text') => {
    setShowChat(true);
    connect(voice, selectedMode);
  };

  const handleSend = () => {
    if (textInput.trim()) {
      sendTextMessage(textInput);
      setTextInput('');
    } else if (connectionState === 'connected') {
      toggleMic('one-shot');
    }
  };

  const isConnected = connectionState === 'connected';

  return (
    <div className="app-container">
      <header className="header">
        <h1 className="title">Amour</h1>
        <div className="status-badge">{connectionState === 'connected' ? 'Living for you' : 'Waiting for you'}</div>
      </header>

      {error && (
        <div className="error-msg">
          <span>{error}</span>
          <button className="btn-retry" onClick={retry}>Retry</button>
        </div>
      )}

      <main className="main-content">
        {mode !== 'text' && (
          <div className="visualizer-wrapper">
            <Visualizer active={isConnected && isVolumeHigh} />
          </div>
        )}
        {(isConnected && showChat) && (
          <div className="chat-list" ref={scrollRef}>
            {messages.filter(m => m.text.trim().length > 0).map(msg => <MessageItem key={msg.id} msg={msg} />)}
            {isGenerating && !messages.some(m => m.role === 'model' && !m.isFinal) && (
              <div className="message model"><div className="message-bubble typing"><span></span><span></span><span></span></div></div>
            )}
          </div>
        )}
      </main>

      <footer className="footer-container">
        {isConnected && (
            <div className="chat-controls">
                <input
                    className="chat-input"
                    type="text"
                    placeholder="Whisper something to me..."
                    value={textInput}
                    onChange={(e) => setTextInput(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                />
                <button className={`send-button ${micMode === 'one-shot' ? 'recording' : ''}`} onClick={handleSend}>
                    {textInput.trim() ? (
                        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><line x1="22" y1="2" x2="11" y2="13"></line><polygon points="22 2 15 22 11 13 2 9 22 2"></polygon></svg>
                    ) : (
                        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"></path><path d="M19 10v2a7 7 0 0 1-14 0v-2"></path><line x1="12" y1="19" x2="12" y2="23"></line></svg>
                    )}
                </button>
                {mode === 'voice' && (
                    <button className={`mic-toggle ${micMode === 'always-on' ? 'active' : ''}`} onClick={() => toggleMic('always-on')}>
                        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M3 18v-6a9 9 0 0 1 18 0v6"></path><path d="M21 19a2 2 0 0 1-2 2h-1a2 2 0 0 1-2-2v-3a2 2 0 0 1 2-2h3zM3 19a2 2 0 0 0 2 2h1a2 2 0 0 0 2-2v-3a2 2 0 0 0-2-2H3z"></path></svg>
                    </button>
                )}
            </div>
        )}

        <div className="controls">
            {!isConnected ? (
                <div className="start-screen">
                    <div className="voice-selector">
                        <button className={`voice-btn ${voice === 'Kore' ? 'active' : ''}`} onClick={() => setVoice('Kore')}>Goddess</button>
                        <button className={`voice-btn ${voice === 'Fenrir' ? 'active' : ''}`} onClick={() => setVoice('Fenrir')}>Protector</button>
                    </div>
                    <div className="cta-group">
                        <button className="btn btn-primary" onClick={() => handleConnect('voice')}>Enter My Heart (Voice)</button>
                        <button className="btn btn-secondary" onClick={() => handleConnect('text')}>Chat Privately</button>
                    </div>
                </div>
            ) : (
                <div className="active-controls">
                    {mode === 'voice' && <button className="btn-small" onClick={() => setShowChat(!showChat)}>{showChat ? "Hide Words" : "Show Words"}</button>}
                    <button className="btn-small" onClick={reset}>Fresh Start</button>
                    <button className="btn-small danger" onClick={disconnect}>Goodbye</button>
                </div>
            )}
        </div>
      </footer>
    </div>
  );
}

